return ['domain'=>NULL,'plural-forms'=>'nplurals=2; plural=(n != 1);','language'=>'es_ES','project-id-version'=>'PublishPress Future Pro','pot-creation-date'=>'2024-07-02T17:41:26+00:00','po-revision-date'=>'2024-07-09 23:19+0200','x-generator'=>'Poedit 3.4.4','messages'=>['PublishPress Future Pro'=>'PublishPress Future Pro','http://wordpress.org/extend/plugins/post-expirator/'=>'http://wordpress.org/extend/plugins/post-expirator/','PublishPress Future allows you to schedule automatic changes to posts, pages and other content types.'=>'PublishPress Future te permite programar cambios automáticos en publicaciones, páginas y otros tipos de contenido.','PublishPress'=>'PublishPress','http://publishpress.com'=>'http://publishpress.com','Post expires at #ACTIONTIME on #ACTIONDATE.'=>'La entrada caduca a las #ACTIONTIME del #ACTIONDATE.','F j, Y'=>'j F, Y','g:i a'=>'g:i a','Displays a message with the date and time of the future action.'=>'Muestra un mensaje con la fecha y hora de la acción de future.','Type the text template and use # to see the autocomplete options with the available placeholders.'=>'Introduce la plantilla de texto y utiliza # para ver las opciones de relleno automático con los marcadores de posición disponibles.','Available placeholders'=>'Marcadores de posición disponibles','Future action block template. Type the text and # to see the autocomplete options.'=>'Plantilla de bloque de acción de Future. Introduce el texto y # para ver las opciones de relleno automático.','Action time'=>'Horario de acción','Action date'=>'Fecha de la acción','Custom statuses'=>'Estados personalizados','Enable custom statuses for the post type.'=>'Activar los estados personalizados para el tipo de contenido.','Enabled'=>'Activado','Disabled'=>'Desactivado','Select all'=>'Seleccionar todo','Unselect all'=>'Deseleccionar todo','Enable Metadata Scheduling'=>'Activar la programación de metadatos','Enable metadata scheduling for the post type'=>'Activar la programación de metadatos para el tipo de contenido:','Checking this option will allow you to use the post metadata to control the scheduling of Future actions in your content.'=>'Al marcar esta opción podrás utilizar los metadatos de la entrada para controlar la programación de las acciones de Future en tu contenido.','Metadata Mapping'=>'Asignación de metadatos','To use the default mapping, please leave the fields empty.'=>'Para utilizar la asignación por defecto, por favor, deja los campos vacíos.','Read more about metadata mapping.'=>'Más información sobre la asignación de metadatos.','Original Metakey'=>'Metakey original','New Metakey'=>'Nueva metakey','Description'=>'Descripción','Hide Future metabox for this post type'=>'Ocultar la caja meta de Future para este tipo de contenido','Checking this option will disable the PublishPress Future metabox. This can prevent conflicts if you\'re using Metadata Scheduling with plugins such as ACF or Pods.'=>'Al marcar esta opción se desactivará la caja meta PublishPress Future. Esto puede evitar conflictos si estás usando la programación de metadatos con plugins como ACF o Pods.','Action Date (Required)'=>'Fecha de la acción (obligatoria)','The date used for scheduling the action. The date must be a unix time stamp or in the \'Y-m-d H:i:s\' format.'=>'La fecha utilizada para programar la acción. La fecha debe ser una marca de tiempo unix o en el formato \'Y-m-d H:i:s\'.','Action Type'=>'Tipo de acción','The type of action to be performed.'=>'El tipo de acción a realizar.','New Post Status'=>'Nuevo estado de la entrada','The new post status to be applied to the post.'=>'El nuevo estado de la entrada que se aplicará a la entrada.','Action Status'=>'Estado de la acción','The status for the action. Anything different than \'saved\' will be considered as not active.'=>'El estado de la acción. Todo lo que no sea «guardado» se considerará no activo.','Taxonomy Name'=>'Nombre de la taxonomía','The taxonomy used for scheduling the action.'=>'La taxonomía utilizada para programar la acción.','Taxonomy Terms'=>'Términos de la taxonomía','The terms used for scheduling the action.'=>'Los términos utilizados para programar la acción.','Form Validation Failure: Sorry, your nonce did not verify.'=>'Error en la validación del formulario: Lo sentimos, tu nonce no ha sido verificado.','Change status to custom status'=>'Cambiar el estado a estado personalizado','Change status to %s'=>'Cambiar estado a %s','Workflow Manual Trigger'=>'Disparador manual del flujo de trabajo','Action Workflows'=>'Flujos de trabajo de acción','Future Workflow'=>'Flujo de trabajo de Future','Add New'=>'Añadir nuevo','Add New Workflow'=>'Añadir nuevo flujo de trabajo','Edit Workflow'=>'Editar flujo de trabajo','New Workflow'=>'Nuevo flujo de trabajo','View Workflow'=>'Ver flujo de trabajo','Search Workflows'=>'Buscar flujos de trabajos','No Workflows found'=>'No se han encontrado flujos de trabajo','No Workflows found in Trash'=>'No se han encontrado flujos de trabajo en la papelera','Parent Workflow:'=>'ZX principal:','All Workflows'=>'Todos los flujos de trabajos','Workflow Archives'=>'Archivos de flujo de trabajo','Insert into workflow'=>'Insertar en el flujo de trabajo','Uploaded to this workflow'=>'Subido a este flujo de trabajo','Filter workflows list'=>'Filtrar la lista de los flujos de trabajos','Workflows list navigation'=>'Navegación de la lista de flujos de trabajos','Action Workflows list'=>'Lista de los flujos de trabajos de acción','Workflow published.'=>'Flujo de trabajo publicado.','Workflow published privately.'=>'Flujo de trabajo publicado como privado.','Workflow reverted to draft.'=>'Flujo de trabajo revertido a borrador.','Workflow scheduled.'=>'Flujo de trabajo programado.','Workflow updated.'=>'Flujo de trabajo actualizado.','Notify when a post is updated'=>'Avisar cuando una entrada está actualizada','Notify the site admin when a post is updated.'=>'Avisar al administrador del sitio cuando una entrada está actualizada.','Unpublish to Draft after a week'=>'Anular la publicación a «Borrador» después de una semana','Change the post status to Draft a week after it was published.'=>'Cambia el estado de la entrada a «Borrador» una semana después de su publicación.','Unpublish and change category after one week'=>'Anular la publicación y cambiar de categoría después de una semana','Move the post to draft and add a category after 15 days.'=>'Mueve la entrada a borrador y añade una categoría después de 15 días.','Add extra categories one month after publishing'=>'Añade categorías adicionales un mes después de la publicación','Sample workflow to add extra categories one month after publishing'=>'Ejemplo de flujo de trabajo para añadir categorías adicionales un mes después de la publicación','Workflow scheduled action'=>'Acción programada de flujo de trabajo','Unschedule workflow recurring scheduled action'=>'Desprograma la acción programada recurrente del flujo de trabajo','Workflow:'=>'Flujo de trabajo:','Trigger: '=>'Disparador: ','Post:'=>'Entrada:','Steps:'=>'Pasos:','Workflow recurring scheduled action'=>'Acción programada recurrente de flujo de trabajo','Welcome to the workflow editor'=>'Bienvenido al editor de flujos de trabajo','In the PublishPress Workflow Editor, each workflow step is presented as a distinct \'node\' in the workflow.'=>'En el editor de flujo de trabajo de PublishPress, cada paso del flujo de trabajo se presenta como un «nodo» distinto en el flujo de trabajo.','Use your imagination'=>'Usa tu imaginación','You\'re free to create very distinct workflows in your site, according to your needs.'=>'You\'re free to create very distinct workflows in your site, according to your needs.','A basic workflow'=>'Un flujo de trabajo básico','Every workflow requires at least two steps connected to each other: one trigger and one action.'=>'Todo flujo de trabajo requiere al menos dos pasos conectados entre sí: un disparador y una acción.','Add steps to your workflow'=>'Añadir pasos a tu flujo de trabajo','Drag and drop steps to add them to your workflow. Connect the steps to create a workflow.'=>'Arrastra y suelta los pasos para añadirlos a tu flujo de trabajo. Conecta los pasos para crear un flujo de trabajo.','Output and input'=>'Salida y entrada','Linked steps can pass data forward as input to the next step.'=>'Los pasos enlazados pueden pasar datos como entrada al siguiente paso.','Customize the workflow'=>'Personalizar el flujo de trabajo','Click on a step to customize it. You can change the step\'s settings in the right sidebar.'=>'Haz clic en un paso para personalizarlo. Puedes cambiar la configuración del paso en la barra lateral derecha.','Workflow validation'=>'Validación del flujo de trabajo','Error messages will appear for any unfilled required settings, missed connections, or invalid values. Select the step to view the corresponding error in the sidebar.'=>'Aparecerán mensajes de error para cualquier ajuste obligatorio sin rellenar, conexiones perdidas o valores no válidos. Selecciona el paso para ver el error correspondiente en la barra lateral.','Publish your workflow'=>'Publica tu flujo de trabajo','When you\'re ready, click the publish button to make your workflow live.'=>'When you\'re ready, click the publish button to make your workflow live.Cuando estés listo, haz clic en el botón «Publicar» para activar tu flujo de trabajo.','Need help?'=>'¿Necesitas ayuda?','If you have any questions or need help, click the help button in the top right corner to access the support resources.'=>'Si tienes alguna duda o necesitas ayuda, haz clic en el botón de ayuda de la esquina superior derecha para acceder a los recursos de soporte.','Triggers'=>'Disparadores','Preview'=>'Vista previa','—'=>'—','No screenshot'=>'Sin captura de pantalla','Post Query'=>'Consulta de entrada','A query to select posts'=>'Una consulta para seleccionar las entradas','Yes'=>'Sí','No'=>'No','Trigger not found: %s'=>'Disparador no encontrado: %s','Trigger Workflow'=>